def symsqrt(mat, cond=None, return_rank=False, inverse=False):
    """Computes the symmetric square root of a symmetric matrix. Throws away small and negative eigenvalues."""

    nan_check(mat)
    s, u = torch.symeig(mat, eigenvectors=True)

    # check_symmetric(mat)

    # todo(y): dedupe with getcond
    cond_dict = {torch.float32: 1e3 * 1.1920929e-07, torch.float64: 1E6 * 2.220446049250313e-16}

    if cond in [None, -1]:
        cond = cond_dict[mat.dtype]

    # Note, this can include negative values, see https://github.com/pytorch/pytorch/issues/25972
    above_cutoff = (s > cond * torch.max(abs(s)))

    if torch.sum(above_cutoff) == 0:
        return torch.zeros_like(mat)

    sigma_diag = torch.sqrt(s[above_cutoff])
    if inverse:
        sigma_diag = 1 / sigma_diag
    u = u[:, above_cutoff]

    B = u @ torch.diag(sigma_diag) @ u.t()

    if torch.sum(torch.isnan(B)) > 0:
        if gl.debug_linalg_crashes:
            dump(mat, '/tmp/symsqrt.txt')
            assert False

    if return_rank:
        return B, len(sigma_diag)
    else:
        return B

def get_whitening_parameters(patches):
    # As a high-level summary, we're basically finding the high-dimensional oval that best fits the data here.
    # We can then later use this information to map the input information to a nicely distributed sphere, where also
    # the most significant features of the inputs each have their own axis. This significantly cleans things up for the
    # rest of the neural network and speeds up training.
    n, c, h, w = patches.shape
    est_covariance = torch.cov(patches.view(n, c * h * w).t())
    eigenvalues, eigenvectors = torch.linalg.eigh(
        est_covariance, UPLO="U"
    )  # this is the same as saying we want our eigenvectors, with the specification that the matrix be an upper triangular matrix (instead of a lower-triangular matrix)
    return eigenvalues.flip(0).view(-1, 1, 1, 1), eigenvectors.t().reshape(
        c * h * w, c, h, w
    ).flip(0)

